def binary_search(arr, target):
    left, right = 0, len(arr) - 1  # Correct initialization for inclusive bounds

    while left <= right:  # Loop while the search space is valid
        mid = (left + right) // 2

        if arr[mid] == target:
            return mid
        elif arr[mid] < target:
            # Target is in the right half
            left = mid + 1
        else:
            # Target is in the left half
            right = mid - 1

    return -1

